#include <stdio.h>
#include <string.h>

int numDistinct(char * s, char * t) {
    int m = strlen(s), n = strlen(t);
    int dp[m + 1][n + 1];
    for (int i = 0; i <= m; i++) {
        dp[i][n] = 1;
    }
    for (int i = m - 1; i >= 0; i--) {
        for (int j = n - 1; j >= 0; j--) {
            if (s[i] == t[j]) {
                dp[i][j] = dp[i + 1][j + 1] + dp[i + 1][j];
            } else {
                dp[i][j] = dp[i + 1][j];
            }
        }
    }
    return dp[0][0];
}

int main() {
    char s[] = "babgbag";
    char t[] = "bag";
    printf("%d\n", numDistinct(s, t));
    return 0;
}

